import { useEffect, useState } from 'react';
import { Link, useParams } from 'react-router-dom';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { toast } from 'sonner';
import { beaconApi } from '@/api/client';
import type { RefineAiActorResult, PauseAiActorResult, ResumeAiActorResult } from '@/api/generated/beacon-api';
import { Icon } from '@/components/Icon';
import { PageHeader } from '@/components/layout/PageHeader';
import { EmptyState } from '@/components/data/EmptyState';
import { ApiError } from '@/lib/api';
import { formatDateTime } from '@/lib/format';
import { useAiActorDetailsQuery, ACTOR_STATUS_LABEL } from './queries';

const STATUS = {
  Draft: 0,
  Active: 1,
  Paused: 2,
  Disabled: 3,
  Archived: 4,
} as const;

function useRefineActor() {
  const qc = useQueryClient();
  return useMutation<RefineAiActorResult, unknown, { id: number; feedback: string }>({
    mutationFn: ({ id, feedback }) => beaconApi().refineAiActor(id, { feedback }),
    onSuccess: (_data, vars) => {
      qc.invalidateQueries({ queryKey: ['ai-actor', vars.id] });
    },
  });
}

function usePauseActor() {
  const qc = useQueryClient();
  return useMutation<PauseAiActorResult, unknown, number>({
    mutationFn: id => beaconApi().pauseAiActor(id),
    onSuccess: (_data, id) => qc.invalidateQueries({ queryKey: ['ai-actor', id] }),
  });
}

function useResumeActor() {
  const qc = useQueryClient();
  return useMutation<ResumeAiActorResult, unknown, number>({
    mutationFn: id => beaconApi().resumeAiActor(id),
    onSuccess: (_data, id) => qc.invalidateQueries({ queryKey: ['ai-actor', id] }),
  });
}

export default function AiActorEditPage() {
  const { id } = useParams();
  const numericId = id ? Number.parseInt(id, 10) : Number.NaN;

  const detail = useAiActorDetailsQuery(Number.isFinite(numericId) ? numericId : undefined);
  const refine = useRefineActor();
  const pause = usePauseActor();
  const resume = useResumeActor();
  const [feedback, setFeedback] = useState('');

  useEffect(() => { setFeedback(''); }, [numericId]);

  if (Number.isNaN(numericId)) {
    return (
      <div className="page">
        <PageHeader title="Edit AI actor" />
        <EmptyState icon={<Icon.Alert size={20} />} title="Invalid actor id" description={String(id)} />
      </div>
    );
  }

  const data = detail.data;
  const status = data?.status ?? 0;
  const isPaused = status === STATUS.Paused;
  const isActive = status === STATUS.Active;

  const handleRefine = async () => {
    const trimmed = feedback.trim();
    if (trimmed.length === 0) {
      toast.error('Provide feedback before refining.');
      return;
    }
    try {
      const result = await refine.mutateAsync({ id: numericId, feedback: trimmed });
      if (result.success) {
        toast.success('Actor refined');
        setFeedback('');
      } else {
        toast.error(result.errorMessage ?? 'Refinement failed');
      }
    } catch (err) {
      const message = err instanceof ApiError
        ? err.body || `Request failed (${err.status})`
        : err instanceof Error ? err.message : 'Unknown error';
      toast.error(message);
    }
  };

  const handlePauseResume = async () => {
    try {
      if (isPaused) {
        await resume.mutateAsync(numericId);
        toast.success('Actor resumed');
      } else {
        await pause.mutateAsync(numericId);
        toast.success('Actor paused');
      }
    } catch (err) {
      const message = err instanceof ApiError
        ? err.body || `Request failed (${err.status})`
        : err instanceof Error ? err.message : 'Unknown error';
      toast.error(message);
    }
  };

  return (
    <div className="page">
      <PageHeader
        title={data?.name ? `Edit: ${data.name}` : 'Edit AI actor'}
        sub={
          <span className="muted">
            <Link to="/ai-actors" className="muted">AI actors</Link>
            <span style={{ margin: '0 6px' }}>/</span>
            <Link to={`/ai-actors/${numericId}`} className="muted">#{numericId}</Link>
            <span style={{ margin: '0 6px' }}>/</span>
            Edit
          </span>
        }
        actions={
          <Link className="btn" to={`/ai-actors/${numericId}`}>
            View
          </Link>
        }
      />

      {detail.isLoading && (
        <div className="card"><div className="card__body"><span className="muted">Loading actor…</span></div></div>
      )}

      {detail.isError && (
        <EmptyState
          icon={<Icon.Alert size={20} />}
          title="Failed to load actor"
          description={detail.error instanceof Error ? detail.error.message : 'Unknown error'}
        />
      )}

      {data && (
        <>
          <div className="card" style={{ marginBottom: 16 }}>
            <div className="card__body">
              <h3 className="card__title" style={{ margin: '0 0 12px' }}>
                <Icon.Bot size={14} /> Status
              </h3>
              <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
                <div>
                  <div className="muted" style={{ fontSize: 12 }}>Current state</div>
                  <div style={{ fontWeight: 600, fontSize: 16 }}>
                    {ACTOR_STATUS_LABEL[status] ?? `status ${status}`}
                  </div>
                </div>
                <div style={{ flex: 1 }} />
                <button
                  type="button"
                  className={isPaused ? 'btn btn--primary' : 'btn'}
                  onClick={handlePauseResume}
                  disabled={pause.isPending || resume.isPending || (!isPaused && !isActive)}
                  title={!isPaused && !isActive ? 'Actor must be active or paused' : undefined}
                >
                  {isPaused
                    ? (resume.isPending ? 'Resuming…' : 'Resume actor')
                    : (pause.isPending ? 'Pausing…' : 'Pause actor')}
                </button>
              </div>
            </div>
          </div>

          <div className="card" style={{ marginBottom: 16 }}>
            <div className="card__body">
              <h3 className="card__title" style={{ margin: '0 0 4px' }}>
                <Icon.Layers size={14} /> Refine actor
              </h3>
              <div className="muted" style={{ fontSize: 12, marginBottom: 12 }}>
                Provide natural-language feedback to refine the actor's instructions. The actor's LLM provider rewrites the prompt based on your input.
              </div>

              <div className="q-field">
                <label className="q-label" htmlFor="ae-feedback">
                  Refinement feedback<span className="q-label__req">*</span>
                </label>
                <textarea
                  id="ae-feedback"
                  rows={6}
                  className="q-input"
                  placeholder="e.g. Focus only on EU customers; ignore historical orders older than 12 months; never join against PII tables."
                  value={feedback}
                  onChange={e => setFeedback(e.target.value)}
                />
              </div>

              <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 12 }}>
                <Link className="btn" to={`/ai-actors/${numericId}`}>Cancel</Link>
                <button
                  type="button"
                  className="btn btn--primary"
                  onClick={handleRefine}
                  disabled={refine.isPending || feedback.trim().length === 0}
                >
                  {refine.isPending ? 'Refining…' : 'Refine actor'}
                </button>
              </div>
            </div>
          </div>

          <div className="card">
            <div className="card__body">
              <h3 className="card__title" style={{ margin: '0 0 12px' }}>
                <Icon.Book size={14} /> Current instructions
              </h3>
              <pre style={{
                background: 'var(--surface-2)',
                border: '1px solid var(--border)',
                borderRadius: 'var(--r-sm)',
                padding: 12,
                fontSize: 12,
                margin: 0,
                whiteSpace: 'pre-wrap',
                maxHeight: 320,
                overflow: 'auto',
              }}>
                {data.instructions ?? '—'}
              </pre>
              {data.lastThinkTime && (
                <div className="muted" style={{ fontSize: 12, marginTop: 8 }}>
                  Last think cycle: <span className="mono">{formatDateTime(data.lastThinkTime)}</span>
                </div>
              )}
            </div>
          </div>
        </>
      )}
    </div>
  );
}
